import React from 'react';
import { EllipsisVerticalIcon } from '@heroicons/react/24/outline';

const UserCard = ({ user, onClick }) => {
  const getStatusColor = (status) => {
    switch (status) {
      case 'online': return 'text-green-500';
      case 'away': return 'text-yellow-500';
      case 'offline': return 'text-gray-500';
      case 'busy': return 'text-red-500';
      default: return 'text-green-500';
    }
  };

  const getStatusDotColor = (status) => {
    switch (status) {
      case 'online': return 'bg-green-500';
      case 'away': return 'bg-yellow-500';
      case 'offline': return 'bg-gray-500';
      case 'busy': return 'bg-red-500';
      default: return 'bg-green-500';
    }
  };

  return (
    <div 
      className="bg-gray-800 rounded-lg p-4 cursor-pointer hover:bg-gray-700 transition-colors"
      onClick={onClick}
    >
      {/* Header com avatar, nome, cargo e menu */}
      <div className="flex items-start gap-3 mb-3">
        <div className="relative">
          <img 
            src={user.avatar} 
            alt={`${user.name} Profile`} 
            className="w-12 h-12 rounded-full object-cover"
          />
          <div className={`absolute -bottom-1 -right-1 w-4 h-4 ${getStatusDotColor(user.status)} rounded-full border-2 border-gray-800`}></div>
        </div>
        <div className="flex-1">
          <h3 className="text-white font-medium text-base">{user.name}</h3>
          <p className="text-gray-400 text-sm">{user.title}</p>
        </div>
        <EllipsisVerticalIcon className="w-5 h-5 text-gray-400" />
      </div>

      {/* Atividade atual */}
      <div className="mb-3">
        <p className="text-white text-sm">{user.bio}</p>
        <p className="text-gray-400 text-xs mt-1">2h</p>
      </div>

      {/* Badge de status */}
      <div className="flex items-center gap-2">
        <div className={`border border-gray-600 rounded px-2 py-1 ${getStatusColor(user.status)}`}>
          <span className="text-xs font-medium">{user.availability}</span>
        </div>
        {/* Ícone adicional se necessário */}
        <div className="w-6 h-6 bg-gradient-to-r from-pink-500 to-blue-500 rounded flex items-center justify-center">
          <div className="w-3 h-3 bg-white rounded-sm"></div>
        </div>
      </div>
    </div>
  );
};

export default UserCard;
